7259 bool ScalarEvolution::isSCEVExprNeverPoison(const Instruction *I) {
7260   // Only proceed if we can prove that I does not yield poison.
7261   if (!programUndefinedIfPoison(I))
7262     return false;
7263 
7264   // At this point we know that if I is executed, then it does not wrap
7265   // according to at least one of NSW or NUW. If I is not executed, then we do
7266   // not know if the calculation that I represents would wrap. Multiple
7267   // instructions can map to the same SCEV. If we apply NSW or NUW from I to
7268   // the SCEV, we must guarantee no wrapping for that SCEV also when it is
7269   // derived from other instructions that map to the same SCEV. We cannot make
7270   // that guarantee for cases where I is not executed. So we need to find a
7271   // upper bound on the defining scope for the SCEV, and prove that I is
7272   // executed every time we enter that scope.  When the bounding scope is a
7273   // loop (the common case), this is equivalent to proving I executes on every
7274   // iteration of that loop.
7275   SmallVector<const SCEV *> SCEVOps;
7276   for (const Use &Op : I->operands()) {
7277     // I could be an extractvalue from a call to an overflow intrinsic.
7278     // TODO: We can do better here in some cases.
7279     if (isSCEVable(Op->getType()))
7280       SCEVOps.push_back(getSCEV(Op));
7281   }
7282   auto *DefI = getDefiningScopeBound(SCEVOps);
7283   return isGuaranteedToTransferExecutionTo(DefI, I);
7284 }
