7199 const Instruction *
7200 ScalarEvolution::getDefiningScopeBound(ArrayRef<const SCEV *> Ops,
7201                                        bool &Precise) {
7202   Precise = true;
7203   // Do a bounded search of the def relation of the requested SCEVs.
7204   SmallSet<const SCEV *, 16> Visited;
7205   SmallVector<const SCEV *> Worklist;
7206   auto pushOp = [&](const SCEV *S) {
7207     if (!Visited.insert(S).second)
7208       return;
7209     // Threshold of 30 here is arbitrary.
7210     if (Visited.size() > 30) {
7211       Precise = false;
7212       return;
7213     }
7214     Worklist.push_back(S);
7215   };
7216 
7217   for (const auto *S : Ops)
7218     pushOp(S);
7219 
7220   const Instruction *Bound = nullptr;
7221   while (!Worklist.empty()) {
7222     auto *S = Worklist.pop_back_val();
7223     if (auto *DefI = getNonTrivialDefiningScopeBound(S)) {
7224       if (!Bound || DT.dominates(Bound, DefI))
7225         Bound = DefI;
7226     } else {
7227       for (const auto *Op : S->operands())
7228         pushOp(Op);
7229     }
7230   }
7231   return Bound ? Bound : &*F.getEntryBlock().begin();
7232 }
